module RefModule(  
    input [31:0] A,  
    input [31:0] B,  
    input enable,  
    output reg [63:0] product  
);  
  wire [31:0] _tap_A = A & {32{1'b1}};

    always @(*) begin  
        if (enable)  
            product = A * B;  
        else  
            product = 64'b0;  
    end  
endmodule
